UPDATE J09A_temp
SET ENTSCHEIDUNG = (
  CASE 
    WHEN HAUS IN (
      SELECT HAUS FROM (
        SELECT HAUS, COUNT(DISTINCT EQUNR) AS cnt
        FROM J09A_temp
        GROUP BY HAUS
      ) WHERE cnt < 3
    ) THEN 'KSA'
    ELSE 'EVU'
  END
);

UPDATE J09A_temp
SET ENTSCHEIDUNG = 'EVU'
WHERE CITY1 IN ('Wiblingwerde', 'Breckerfeld');

